import { test, expect } from '@playwright/test';

test('verify header links and targets on mobile', async ({ page }) => {
  // Set mobile viewport
  await page.setViewportSize({ width: 375, height: 812 });

  // Navigate to the target URL
  await page.goto('http://localhost:3002');

  // Verify Home link (logo/brand) target
  const homeLink = page.locator('nav').getByRole('link', { name: 'okwasniewski' });
  await expect(homeLink).toHaveAttribute('href', '/');
  await homeLink.click();
  expect(page.url()).toBe('http://localhost:3002/');

  // Verify Blog link target
  const blogLink = page.locator('nav').getByRole('link', { name: 'blog' });
  await expect(blogLink).toHaveAttribute('href', '/blog');
  await blogLink.click();
  expect(page.url()).toContain('/blog');
  await page.goBack();

  // Verify Portfolio link target
  const portfolioLink = page.locator('nav').getByRole('link', { name: 'portfolio' });
  await expect(portfolioLink).toHaveAttribute('href', '/portfolio');
  await portfolioLink.click();
  expect(page.url()).toContain('/portfolio');
  await page.goBack();

  // Verify Videos link target (Expected to fail due to typo /vidoes)
  const videosLink = page.locator('nav').getByRole('link', { name: 'videos' });
  const videosHref = await videosLink.getAttribute('href');
  expect(videosHref).toBe('/videos'); // This fails as it is '/vidoes'

  // Verify Contact link target (Expected to fail if on 404 page due to typo /contcat)
  const contactLink = page.locator('nav').getByRole('link', { name: 'contact' });
  const contactHref = await contactLink.getAttribute('href');
  expect(contactHref).toBe('/contact');
});
